#include <omp.h>
#include <stdlib.h>
#include <stdio.h>
#include "../common.h"

void kernel_cpu_2(int cores_arg,
                  knode *knodes,
                  long knodes_elem,
                  int order,
                  long maxheight,
                  int count,
                  long *currKnode,
                  long *offset,
                  long *lastKnode,
                  long *offset_2,
                  int *start,
                  int *end,
                  int *recstart,
                  int *reclength)
{
    int total_threads = count * order;

    #pragma omp parallel num_threads(total_threads)
    {
        int global_id = omp_get_thread_num();
        int bid = global_id / order;
        int thid = global_id % order;

        if(bid < count) {
            for(int i = 0; i < maxheight; i++) {
                if(thid < knodes[currKnode[bid]].num_keys - 1) {
                    if(knodes[currKnode[bid]].keys[thid] <= start[bid] && 
                       knodes[currKnode[bid]].keys[thid+1] > start[bid]) {
                        if(knodes[currKnode[bid]].indices[thid] < knodes_elem) {
                            offset[bid] = knodes[currKnode[bid]].indices[thid];
                        }
                    }
                }

                if(thid < knodes[lastKnode[bid]].num_keys - 1) {
                    if(knodes[lastKnode[bid]].keys[thid] <= end[bid] && 
                       knodes[lastKnode[bid]].keys[thid+1] > end[bid]) {
                        if(knodes[lastKnode[bid]].indices[thid] < knodes_elem) {
                            offset_2[bid] = knodes[lastKnode[bid]].indices[thid];
                        }
                    }
                }

                #pragma omp barrier

                if(thid == 0) {
                    currKnode[bid] = offset[bid];
                    lastKnode[bid] = offset_2[bid];
                }

                #pragma omp barrier
            }

            if(thid < knodes[currKnode[bid]].num_keys) {
                if(knodes[currKnode[bid]].keys[thid] == start[bid]) {
                    recstart[bid] = knodes[currKnode[bid]].indices[thid];
                }
            }

            #pragma omp barrier

            if(thid < knodes[lastKnode[bid]].num_keys) {
                if(knodes[lastKnode[bid]].keys[thid] == end[bid]) {
                    reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
                }
            }
        }
    }
}
